import java.util.HashSet;

public class UniqueVisitors {
    public static void main(String[] args) {
        HashSet<String> visitors = new HashSet<>();

        String[] log = {"alice", "bob", "alice", "carol", "bob", "dave", "alice"};

        for (String user : log) {
            visitors.add(user);  // duplicates are ignored
        }

        System.out.println("Total log entries: " + log.length);
        System.out.println("Unique visitors: " + visitors.size());
        System.out.println("Visitor set: " + visitors);
    }
}
